 73	export const CheckConfigComp: React.FC<CheckModalProps> = (props: CheckModalProps) => {
 74	  const { t } = useKialiTranslation();
 75	  const [loading, setLoading] = React.useState(false);
 76	  const [error, setError] = React.useState<string | null>(null);
 77	  const externalUrl = validateExternalUrl(props.externalServices, props.kiosk, props.tracingInfo);
 78	
 79	  const labels = {
 80	    namespaceSelector: 'NamespaceSelector',
 81	    provider: 'Provider',
 82	    url: 'InternalUrl',
 83	    useGRPC: 'UseGRPC'
 84	  };
 85	
 86	  React.useEffect(() => {
 87	    if (!props.tracingDiagnose) {
 88	      fetchCheckService();
 89	    }
 90	    // eslint-disable-next-line react-hooks/exhaustive-deps
 91	  }, []);
 92	
 93	  const fetchCheckService = async (): Promise<void> => {
 94	    setLoading(true);
 95	    setError(null);
 96	
 97	    return API.getDiagnoseStatus(props.cluster)
 98	      .then(response => {
 99	        props.setTracingDiagnose(response.data);
100	        setLoading(false);
101	      })
102	      .catch(err => {
103	        setLoading(false);
104	        const errString = err.response.data.error ? err.response.data.error : err;
105	        setError(`${errString}`);
106	      });
107	  };
108	
109	  const handleCheckService = async (): Promise<void> => {
110	    fetchCheckService();
111	  };
112	
113	  return (
114	    <div
115	      id="discovery-tab-content"
116	      style={{ display: 'flex', flexDirection: 'column', height: '600px', paddingTop: '1em' }}
117	    >
118	      <div style={{ flexGrow: 1, overflowY: 'auto' }}>
119	        {props.tracingDiagnose && (
120	          <>
121	            <span style={{ color: 'green' }}>{props.tracingDiagnose.message}</span>
122	            <div style={{ marginTop: '1em' }}>
123	              <span>{t('Possible configuration(s) found for external_services.tracing')}:</span>
124	            </div>
125	          </>
126	        )}
127	        {error && (
128	          <div>
129	            <span style={{ color: 'red' }}>{error}</span>
130	          </div>
131	        )}
132	        {props.tracingDiagnose?.validConfig && (
133	          <>
134	            <div style={{ margin: '0.5em 0', display: 'flex' }}>
135	              <span>
136	                {props.tracingDiagnose?.validConfig.length === 0 && <>No configurations found. See logs for details</>}
137	              </span>
138	            </div>
139	            <div id="valid-configurations">
140	              {props.tracingDiagnose?.validConfig?.map((item, i) => (
141	                <>
142	                  <div className={configStyle}>
143	                    {Object.keys(item).map(key => {
144	                      if (labels[key] !== undefined && item[key] != null) {
145	                        return (
146	                          <span className={blockDisplay}>
147	                            <span className={blueDisplay}>{labels[key]}:</span> {item[key].toString()}
148	                          </span>
149	                        );
150	                      }
151	                      return null;
152	                    })}
153	                    {item.warning && <span style={{ color: 'red' }}>{item.warning}</span>}
154	                  </div>
155	                  {props.tracingDiagnose?.validConfig && i < props.tracingDiagnose?.validConfig?.length - 1 && (
156	                    <div style={{ padding: '0 0 10px 5px' }}>---</div>
157	                  )}
158	                </>
159	              ))}
160	            </div>
161	          </>
162	        )}
163	        {props.tracingDiagnose?.validConfig && externalUrl && (
164	          <div>
165	            <span className={configStyle}>{externalUrl}</span>
166	          </div>
167	        )}
168	        {props.tracingDiagnose?.logLine && (
169	          <>
170	            <div style={{ margin: '1em 0' }}>
171	              <Title headingLevel="h4" size="lg" style={{ paddingBottom: '10px' }}>
172	                {t('Logs')}:
173	              </Title>
174	              <div className={containerStyle} id={'configuration-logs'}>
175	                {props.tracingDiagnose.logLine.map(log => (
176	                  <>
177	                    <div>
178	                      <span>
179	                        <span className={greyDisplay}>{log.time.substring(0, 19)}</span>
180	                        <span className={classes(blueDisplay, padding)}>[{log.test}]</span>
181	                        {log.result}
182	                      </span>
183	                    </div>
184	                  </>
185	                ))}
186	              </div>
187	            </div>
188	          </>
189	        )}
190	      </div>
191	      <div>
192	        <Button
193	          onClick={handleCheckService}
194	          disabled={loading}
195	          variant={ButtonVariant.secondary}
196	          style={{ marginRight: '5px' }}
197	        >
198	          {t('Rediscover')}
199	        </Button>
200	        {loading && <Spinner id="discover-spinner" size="sm" />}
201	      </div>
202	    </div>
203	  );
204	};
205	
206	const mapStateToProps = (state: KialiAppState): ReduxProps => {
207	  return {
208	    externalServices: state.statusState.externalServices,
209	    kiosk: state.globalState.kiosk,
210	    tracingDiagnose: state.tracingState.diagnose,
211	    tracingInfo: state.tracingState.info
212	  };
213	};
214	
215	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
216	  setTracingDiagnose: bindActionCreators(TracingActions.setDiagnose, dispatch)
217	});
218	
219	export const DiscoveryTracingConfig = connect(mapStateToProps, mapDispatchToProps)(CheckConfigComp);

